    public function fetch_markets($params = array ()): PromiseInterface {
        return Async\async(function () use ($params) {
            /**
             * fetches kalshi markets; with a query it resolves the query via the $events endpoint and returns the matched events' markets, otherwise it pages the markets listing
             *
             * @see https://trading-api.readme.io/reference/getmarkets
             *
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @param {string} [$params->query] a single search query; resolved against the $events endpoint (event title/ticker), then the matched events' markets are returned
             * @param {string[]} [$params->queries] multiple search $queries (alternative to query); markets from any matching event are returned
             * @param {int} [$params->limit] for an unscoped listing (no query), the max number of markets to collect (defaults to options.maxFetchMarketsLimit, 1000)
             * @return {array[]} an array of objects representing market data
             */
            $queries = $this->parse_search_queries($params);
            $queriesLength = count($queries);
            // kalshi's public markets endpoint has no free-text search, so a query would otherwise
            // force a client-side scan of every open market (thousands, paged 1000 at a time, which
            // hangs). Resolve the query against the $events endpoint instead — it is bounded by
            // maxPages, scoped server-side, supports multiple topics, and returns each event's $parsed
            // markets — then flatten those markets.
            if ($queriesLength > 0) {
                $eventParams = $this->omit($params, array( 'limit' ));
                $events = Async\await($this->fetch_events($eventParams));
                $eventsLength = count($events);
                $queryMarkets = array();
                for ($ei = 0; $ei < $eventsLength; $ei++) {
                    $eventMarkets = $this->safe_list($events[$ei], 'markets', array());
                    $eventMarketsLength = count($eventMarkets);
                    for ($mi = 0; $mi < $eventMarketsLength; $mi++) {
                        $queryMarkets[] = $eventMarkets[$mi];
                    }
                }
                return $queryMarkets;
            }
            $rest = $this->omit($params, array( 'query', 'queries', 'limit' ));
            // no query => page the markets listing directly. Cap the total collected so an unscoped
            // loadMarkets cannot run away through every kalshi market via the $cursor->
            $maxMarkets = $this->safe_integer($params, 'limit', $this->safe_integer($this->options, 'maxFetchMarketsLimit', 1000));
            $flatMarkets = array();
            $eventsDict = array();
            $cursor = null;
            $limit = $this->safe_integer($this->options, 'maxFetchMarketsLimit', 1000);
            // default to tradeable (open) markets; kalshi has thousands of closed/settled markets and
            // an unfiltered $cursor pages through those, so loadMarkets would otherwise return mostly
            // closed markets. Pass $params->status (e.g. 'closed', 'settled', 'unopened') to override
            $status = $this->safe_string($rest, 'status', 'open');
            while (true) {
                $request = array( 'limit' => $limit, 'status' => $status );
                if ($cursor !== null) {
                    $request['cursor'] = $cursor;
                }
                $response = Async\await($this->kalshiPublicGetMarkets ($this->extend($request, $rest)));
                $rawMarkets = $this->safe_list($response, 'markets', array());
                $rawMarketsLength = count($rawMarkets);
                for ($i = 0; $i < count($rawMarkets); $i++) {
                    $raw = $rawMarkets[$i];
                    $parsed = $this->parse_binary_market_to_outcomes($raw);
                    $eventTicker = $this->safe_string($raw, 'event_ticker');
                    $eventTitle = $this->safe_string($raw, 'title', $eventTicker);
                    $eventKey = $eventTitle ? $this->shorten_slug($eventTitle) : null;
                    for ($j = 0; $j < count($parsed); $j++) {
                        $m = $parsed[$j];
                        $flatMarkets[] = $m;
                        if ($eventKey) {
                            if (!(is_array($eventsDict) && array_key_exists($eventKey, $eventsDict))) {
                                $eventsDict[$eventKey] = array(
                                    'id' => $eventTicker,
                                    'slug' => $eventTicker,
                                    'event' => $eventKey,
                                    'title' => $eventTitle,
                                    'markets' => array(),
                                );
                            }
                            $eventEntry = $eventsDict[$eventKey];
                            $eventEntry['markets'][] = $m;
                        }
                    }
                }
                $cursor = $this->safe_string($response, 'cursor');
                $collectedLength = count($flatMarkets);
                if (!$cursor || $rawMarketsLength < $limit || $collectedLength >= $maxMarkets) {
                    break;
                }
            }
            $this->events = $eventsDict;
            $flatMarketsLength = count($flatMarkets);
            if ($flatMarketsLength > $maxMarkets) {
                return $this->array_slice($flatMarkets, 0, $maxMarkets);
            }
            return $flatMarkets;
        }) ();
    }

    public function parse_binary_market_to_outcomes(array $raw): array {
        return array( $this->parse_market($raw) );
    }

    public function fetch_outcome(string $outcomeSymbol): PromiseInterface {
        return Async\async(function () use ($outcomeSymbol) {
            /**
             * @ignore
             * resolves a single outcome on demand instead of bulk-loading. kalshi has tens of
             * thousands of markets, so a cache miss fetches just the requested market by ticker and merges
             * it into the cache (the same outcome lookups loadOutcomes builds), so repeat lookups are free
             * @param {string} $outcomeSymbol an outcome id — a kalshi ticker, or a ticker with a '-NO' $suffix
             * @return {array} the resolved outcome object
             */
            $symbolLength = count($outcomeSymbol);
            $suffix = mb_substr($outcomeSymbol, $symbolLength - 3);
            $isNo = ($suffix === '-NO');
            $baseTicker = $isNo ? mb_substr($outcomeSymbol, 0, $symbolLength - 3 - 0) : $outcomeSymbol;
            $response = null;
            try {
                $response = Async\await($this->kalshiPublicGetMarketsTicker (array( 'ticker' => $baseTicker )));
            } catch (Exception $e) {
                // an unknown ticker — or a unified handle passed on a cold cache — returns 'not_found',
                // which handleErrors maps to BadSymbol. surface a clear hint; $network failures propagate.
                if ($e instanceof BadSymbol) {
                    throw new BadSymbol($this->id . ' could not resolve outcome ' . $outcomeSymbol . ' — pass an outcomeId, or call fetchEvents ()/loadOutcomes () first');
                }
                throw $e;
            }
            $rawMarket = $this->safe_dict($response, 'market', $response);
            $parsed = $this->parse_market($rawMarket);
            if ($this->markets === null) {
                $this->markets = $this->create_safe_dictionary();
            }
            $this->markets[$parsed['symbol']] = $parsed;
            $this->populate_outcomes();
            return $this->outcome($outcomeSymbol);
        }) ();
    }

    public function handle_errors(int $code, string $reason, string $url, string $method, array $headers, string $body, mixed $response, mixed $requestHeaders, mixed $requestBody) {
        // kalshi returns array( "error" => array( "code" => "...", ... ) ) with a 4xx; map known codes to ccxt
        // errors (e.g. not_found -> '\\ccxt\\BadSymbol') so callers can distinguish them from a transport
        // outage (the base otherwise maps a bare 404 to ExchangeNotAvailable). unmapped codes fall
        // through to the base http-status handling.
        if (!$response) {
            return null;
        }
        $error = $this->safe_dict($response, 'error');
        if ($error !== null) {
            $errorCode = $this->safe_string($error, 'code');
            $feedback = $this->id . ' ' . $body;
            $this->throw_exactly_matched_exception($this->exceptions['exact'], $errorCode, $feedback);
            $this->throw_broadly_matched_exception($this->exceptions['broad'], $errorCode, $feedback);
        }
        return null;
    }

    public function parse_market(array $raw): array {
        // {
        //    "can_close_early":true,
        //    "close_time":"2029-07-01T14:00:00Z",
        //    "created_time":"0001-01-01T00:00:00Z",
        //    "early_close_condition":"This market will close and expire early if the event occurs.",
        //    "event_ticker":"KXBALANCE-29",
        //    "expected_expiration_time":"2029-07-01T14:00:00Z",
        //    "expiration_time":"2029-07-01T14:00:00Z",
        //    "expiration_value":"",
        //    "fractional_trading_enabled":false,
        //    "last_price_dollars":"0.1100",
        //    "latest_expiration_time":"2029-07-01T14:00:00Z",
        //    "liquidity_dollars":"0.0000",
        //    "market_type":"binary",
        //    "no_ask_dollars":"0.9000",
        //    "no_bid_dollars":"0.8900",
        //    "no_sub_title":"During Trump's term",
        //    "notional_value_dollars":"1.0000",
        //    "open_interest_fp":"16353.00",
        //    "open_time":"2025-01-03T15:00:00Z",
        //    "previous_price_dollars":"0.0000",
        //    "previous_yes_ask_dollars":"0.0000",
        //    "previous_yes_bid_dollars":"0.0000",
        //    "price_level_structure":"linear_cent",
        //    "price_ranges":array(
        //        {
        //            "end":"1.0000",
        //            "start":"0.0000",
        //            "step":"0.0100"
        //        }
        //    ),
        //    "response_price_units":"usd_cent",
        //    "result":"",
        //    "rules_primary":"If there is not a budget deficit for any of fiscal years 2025, 2026, 2027, or 2028, then the market resolves to Yes.",
        //    "rules_secondary":"",
        //    "settlement_timer_seconds":"1800",
        //    "status":"active",
        //    "subtitle":"",
        //    "tick_size":"1",
        //    "ticker":"KXBALANCE-29",
        //    "title":"Will Trump balance the budget?",
        //    "updated_time":"0001-01-01T00:00:00Z",
        //    "volume_24h_fp":"85.00",
        //    "volume_fp":"40208.00",
        //    "yes_ask_dollars":"0.1100",
        //    "yes_ask_size_fp":"",
        //    "yes_bid_dollars":"0.1000",
        //    "yes_bid_size_fp":"",
        //    "yes_sub_title":"During Trump's term"
        // }
        $ticker = $this->safe_string($raw, 'ticker');
        $eventTicker = $this->safe_string($raw, 'event_ticker');
        $subtitle = $this->safe_string($raw, 'subtitle', $this->safe_string($raw, 'title'));
        // markets use $status 'active' while events use 'open'
        $status = $this->safe_string($raw, 'status');
        $active = ($status === 'active') || ($status === 'open');
        $endDate = $this->safe_string($raw, 'expiration_time');
        $volume = $this->safe_number($raw, 'volume');
        $liquidity = $this->safe_number($raw, 'liquidity');
        $openInt = $this->safe_number($raw, 'open_interest');
        // Derive series $ticker => drop last hyphen-segment from event_ticker
        $eventParts = array();
        if ($eventTicker) {
            $eventParts = explode('-', $eventTicker);
        }
        $seriesTicker = $eventTicker;
        $eventPartsLength = count($eventParts);
        if ($eventPartsLength > 1) {
            $seriesParts = $this->array_slice($eventParts, 0, $eventPartsLength - 1);
            $seriesTicker = implode('-', $seriesParts);
        }
        // market symbol (no outcome suffix)
        $subtitleOrTicker = ($subtitle !== null) ? $subtitle : $ticker;
        $marketSymbol = $this->slug_to_market_symbol($eventTicker, $subtitleOrTicker);
        // kalshi exposes the per-market price tick via price_rangesarray().step (a dollar value,
        // e.g. "0.0010" for deci-cent markets, "0.0100" for cent markets); older responses
        // used tick_size (in cents). amount is a whole number of contracts
        $priceRanges = $this->safe_list($raw, 'price_ranges', array());
        $firstRange = $this->safe_dict($priceRanges, 0, array());
        $stepDollars = $this->safe_string($firstRange, 'step');
        $pricePrecision = $this->parse_number(Precise::string_div($this->safe_string($raw, 'tick_size', '1'), '100'));
        if ($stepDollars !== null) {
            $pricePrecision = $this->parse_number($stepDollars);
        }
        $precision = array(
            'amount' => 1,
            'price' => $pricePrecision,
        );
        // Build $outcomes
        $outcomeLabels = array( 'YES', 'NO' );
        $outcomeIds = array( $ticker, $ticker . '-NO' );
        $outcomes = array();
        for ($oi = 0; $oi < count($outcomeLabels); $oi++) {
            $label = $outcomeLabels[$oi];
            $outcomeHandle = $marketSymbol . ':' . $label;
            $outcomes[] = array(
                'id' => $outcomeIds[$oi],
                'outcomeId' => $outcomeIds[$oi],
                'outcome' => $outcomeHandle,
                'market' => $marketSymbol,
                'label' => $label,
                'active' => $active,
                'precision' => $precision,
                'info' => array(
                    'ticker' => $ticker,
                    'eventTicker' => $eventTicker,
                    'seriesTicker' => $seriesTicker,
                    'subtitle' => $subtitle,
                    'outcomeLabel' => $label,
                    'volume' => $volume,
                    'liquidity' => $liquidity,
                    'openInterest' => $openInt,
                ),
            );
        }
        return array(
            'id' => $ticker,
            'symbol' => $marketSymbol,
            'base' => 'USD',
            'quote' => 'USD',
            'settle' => null,
            'baseId' => $ticker,
            'quoteId' => 'USD',
            'settleId' => null,
            'type' => 'prediction',
            'marketType' => 'binary',
            'executionModel' => 'clob',
            'spot' => false,
            'margin' => false,
            'swap' => false,
            'future' => false,
            'option' => false,
            'prediction' => true,
            'active' => $active,
            'contract' => false,
            'linear' => null,
            'inverse' => null,
            'contractSize' => null,
            'expiry' => $endDate ? $this->parse8601($endDate) : null,
            'expiryDatetime' => $endDate,
            'strike' => null,
            'optionType' => null,
            'taker' => 0.07,
            'maker' => 0.0,
            'percentage' => true,
            'tierBased' => false,
            'feeSide' => 'get',
            'precision' => $precision,
            'limits' => array(
                'leverage' => array( 'min' => 1, 'max' => 1 ),
                'amount' => array( 'min' => 1, 'max' => null ),
                'price' => array( 'min' => 0.01, 'max' => 0.99 ),
                'cost' => array( 'min' => null, 'max' => null ),
            ),
            'outcomes' => $outcomes,
            'info' => $this->extend($raw, array(
                'ticker' => $ticker,
                'eventTicker' => $eventTicker,
                'seriesTicker' => $seriesTicker,
                'subtitle' => $subtitle,
                'volume' => $volume,
                'liquidity' => $liquidity,
                'openInterest' => $openInt,
            )),
            'created' => null,
        );
    }

    public function fetch_ticker(?string $outcome, $params = array ()): PromiseInterface {
        return Async\async(function () use ($outcome, $params) {
            /**
             * fetches the current market price and bid/ask for a single kalshi $outcome
             *
             * @see https://docs.kalshi.com/api-reference/market/get-market
             *
             * @param {string} $outcome the unified $outcome like TRUMP_BRING_BACK_MANUFACTURING:YES or outcomeId like KXGDPSHAREMANU-29
             * @param {array} [$params] extra parameters specific to the exchange API endpoint
             * @return {array} a [$ticker structure](https://docs.ccxt.com/#/?id=$ticker-structure)
             */
            Async\await($this->load_outcome($outcome));
            $outcomeObj = $this->outcome($outcome);
            $ticker = $this->safe_string($outcomeObj['info'], 'ticker');
            $request = array(
                'ticker' => $ticker,
            );
            $response = Async\await($this->kalshiPublicGetMarketsTicker ($this->extend($request, $params)));
            //
            //     {
            //         "market" => {
            //             "can_close_early" => true,
            //             "close_time" => "2029-06-30T03:59:00Z",
            //             "created_time" => "2025-06-05T17:55:43.779104Z",
            //             "early_close_condition" => "This market will close and expire early if the event occurs.",
            //             "event_ticker" => "KXGDPSHAREMANU-29",
            //             "expected_expiration_time" => "2029-06-30T14:00:00Z",
            //             "expiration_time" => "2029-07-07T14:00:00Z",
            //             "expiration_value" => "",
            //             "floor_strike" => "13.1",
            //             "fractional_trading_enabled" => true,
            //             "last_price_dollars" => "0.1980",
            //             "latest_expiration_time" => "2029-07-07T14:00:00Z",
            //             "liquidity_dollars" => "0.0000",
            //             "market_type" => "binary",
            //             "no_ask_dollars" => "0.8890",
            //             "no_bid_dollars" => "0.8030",
            //             "no_sub_title" => "Before 2029",
            //             "notional_value_dollars" => "1.0000",
            //             "open_interest_fp" => "11077.21",
            //             "open_time" => "2025-06-05T18:00:00Z",
            //             "previous_price_dollars" => "0.1980",
            //             "previous_yes_ask_dollars" => "0.1970",
            //             "previous_yes_bid_dollars" => "0.1110",
            //             "price_level_structure" => "deci_cent",
            //             "price_ranges" => array(
            //                 {
